	const int number = 100;
	// number = 200;

	int number1 = 100;
	int number2 = 200;

	// 常量指针（const 在 * 之前,地址可以被重新赋值，但是值不能改变）
	// int const * n_p = &number2;
	// n_p = &number1;
	// printf("n_p = %p",n_p); // 地址是可以重新被赋值的
	// *n_p = 300; // 值不能改变

	// 指针常量（const 在 * 之后,地址不可以被重新赋值，但是值可以改变）
	int* const n_p = &number2;
